import{_ as e,o as t,c as l,a2 as i}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"FATCA","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"compliance-and-tax/fatca.md","filePath":"zh-CN/compliance-and-tax/fatca.md"}'),r={name:"compliance-and-tax/fatca.md"};function o(n,a,c,s,h,d){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="fatca" tabindex="-1">FATCA <a class="header-anchor" href="#fatca" aria-label="Permalink to &quot;FATCA&quot;">​</a></h1><p>美国海外账户税收合规法案要求，客户税务身份确认及申报责任说明。</p><h2 id="什么是-fatca" tabindex="-1">什么是 FATCA <a class="header-anchor" href="#什么是-fatca" aria-label="Permalink to &quot;什么是 FATCA&quot;">​</a></h2><p>FATCA（Foreign Account Tax Compliance Act，海外账户税收合规法案）是美国为防止美国纳税人逃避美国税项而制定的法规，由美国财政部和美国国税局（IRS）制定。</p><p>所有银行及金融机构都将受到 FATCA 影响。长桥承诺在所有经营业务的国家/地区全面遵守 FATCA。</p><h2 id="为何与我有关" tabindex="-1">为何与我有关 <a class="header-anchor" href="#为何与我有关" aria-label="Permalink to &quot;为何与我有关&quot;">​</a></h2><p>根据 FATCA，您需向长桥声明及确认您的税务身份，财务资料可能被上报。</p><p>所有客户均需填写：</p><ul><li><strong>W-8 系列表格</strong>：确认非美国税务身份</li><li><strong>W-9 表格</strong>：确认美国税务身份</li></ul><p>只有美国账户持有人的资料会被申报。</p><h2 id="受影响的客户" tabindex="-1">受影响的客户 <a class="header-anchor" href="#受影响的客户" aria-label="Permalink to &quot;受影响的客户&quot;">​</a></h2><p>FATCA 影响就美国税务而言视为「美国人士」的个人及商业客户，包括但不限于：</p><ul><li>美国公民（包括在美国出生但在其他国家/地区居住且未放弃公民身份的个人）</li><li>在美国居住的人士（包括美国绿卡持有人）</li><li>每年在美国居住较长时间的特定人士</li><li>美国公司、美国合伙、美国遗产及美国信托</li></ul><h2 id="客户责任" tabindex="-1">客户责任 <a class="header-anchor" href="#客户责任" aria-label="Permalink to &quot;客户责任&quot;">​</a></h2><ul><li>开户时填写适用表格确认是否美国税务身份</li><li>之后每 3 年重新确认</li><li>3 年期间有任何变动应及早更新</li></ul><p>非美国人士须就源于美国的特定收款以预扣税方式缴纳税款，可通过 W-8 表格申请税务协定优惠。</p><h2 id="更多信息" tabindex="-1">更多信息 <a class="header-anchor" href="#更多信息" aria-label="Permalink to &quot;更多信息&quot;">​</a></h2><p><a href="https://www.irs.gov/businesses/corporations/foreign-account-tax-compliance-act-fatca" target="_blank" rel="noreferrer">详情请参阅美国国税局网站</a></p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/compliance-and-tax">合规与税务</a></li></ul>',20)])])}const f=e(r,[["render",o]]);export{u as __pageData,f as default};
